1	function toKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function fromKey(key: string): [number, number] {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	}
9	
10	function neighbors(x: number, y: number): [number, number][] {
11	  const result: [number, number][] = [];
12	  for (let dx = -1; dx <= 1; dx++) {
13	    for (let dy = -1; dy <= 1; dy++) {
14	      if (dx === 0 && dy === 0) continue;
15	      result.push([x + dx, y + dy]);
16	    }
17	  }
18	  return result;
19	}
20	
21	function countLiveNeighbors(x: number, y: number, alive: Set<string>): number {
22	  return neighbors(x, y).filter(([nx, ny]) => alive.has(toKey(nx, ny))).length;
23	}
24	
25	export function nextGeneration(cells: [number, number][]): [number, number][] {
26	  const alive = new Set(cells.map(([x, y]) => toKey(x, y)));
27	
28	  const survivors = cells.filter(([x, y]) => {
29	    const count = countLiveNeighbors(x, y, alive);
30	    return count === 2 || count === 3;
31	  });
32	
33	  const deadNeighbors = new Set<string>();
34	  for (const [x, y] of cells) {
35	    for (const [nx, ny] of neighbors(x, y)) {
36	      const key = toKey(nx, ny);
37	      if (!alive.has(key)) deadNeighbors.add(key);
38	    }
39	  }
40	
41	  const births: [number, number][] = [];
42	  for (const key of deadNeighbors) {
43	    const [x, y] = fromKey(key);
44	    if (countLiveNeighbors(x, y, alive) === 3) {
45	      births.push([x, y]);
46	    }
47	  }
48	
49	  return [...survivors, ...births];
50	}
